enum LoginError: Error { case wrongPass }

func login(pass: String) throws {
    if pass != "1234" { throw LoginError.wrongPass }
    print("Login successful!")
}

// Safely handling the dangerous function
do {
    try login(pass: "wrong_word")
    print("Let's play!")
} catch {
    print("Alert: Incorrect Password. Try again.")
}
